import {
  aiCoachUsageStatusCanUse,
  AiCoachUsageStatus,
  ballUsageStatusCanAnalyze,
  ballUsageStatusShouldWarn,
  BallUsageStatus,
  teamPlanStatusIsValid,
  TeamPlanStatus,
} from '../team-status';

describe('team-status', () => {
  describe('TeamPlanStatus', () => {
    it('enum values should match expected strings', () => {
      expect(TeamPlanStatus.NO_CONTRACT).toBe('no_contract');
      expect(TeamPlanStatus.NEXT_PLAN_PENDING).toBe('next_plan_pending');
      expect(TeamPlanStatus.EXPIRED).toBe('expired');
      expect(TeamPlanStatus.EXPIRING_SOON).toBe('expiring_soon');
      expect(TeamPlanStatus.OK).toBe('ok');
    });
  });

  describe('BallUsageStatus', () => {
    it('enum values should match expected strings', () => {
      expect(BallUsageStatus.LIMIT_REACHED).toBe('limit_reached');
      expect(BallUsageStatus.LIMIT_APPROACHING).toBe('limit_approaching');
      expect(BallUsageStatus.OK).toBe('ok');
    });
  });

  describe('AiCoachUsageStatus', () => {
    it('enum values should match expected strings', () => {
      expect(AiCoachUsageStatus.LIMIT_REACHED).toBe('limit_reached');
      expect(AiCoachUsageStatus.LIMIT_APPROACHING).toBe('limit_approaching');
      expect(AiCoachUsageStatus.OK).toBe('ok');
    });
  });

  describe('teamPlanStatusIsValid', () => {
    it('should return true for EXPIRING_SOON', () => {
      expect(teamPlanStatusIsValid(TeamPlanStatus.EXPIRING_SOON)).toBe(true);
    });

    it('should return true for OK', () => {
      expect(teamPlanStatusIsValid(TeamPlanStatus.OK)).toBe(true);
    });

    it('should return false for NO_CONTRACT', () => {
      expect(teamPlanStatusIsValid(TeamPlanStatus.NO_CONTRACT)).toBe(false);
    });

    it('should return false for NEXT_PLAN_PENDING', () => {
      expect(teamPlanStatusIsValid(TeamPlanStatus.NEXT_PLAN_PENDING)).toBe(false);
    });

    it('should return false for EXPIRED', () => {
      expect(teamPlanStatusIsValid(TeamPlanStatus.EXPIRED)).toBe(false);
    });
  });

  describe('ballUsageStatusCanAnalyze', () => {
    it('should return true for LIMIT_APPROACHING', () => {
      expect(ballUsageStatusCanAnalyze(BallUsageStatus.LIMIT_APPROACHING)).toBe(true);
    });

    it('should return true for OK', () => {
      expect(ballUsageStatusCanAnalyze(BallUsageStatus.OK)).toBe(true);
    });

    it('should return false for LIMIT_REACHED', () => {
      expect(ballUsageStatusCanAnalyze(BallUsageStatus.LIMIT_REACHED)).toBe(false);
    });
  });

  describe('ballUsageStatusShouldWarn', () => {
    it('should return true for LIMIT_APPROACHING', () => {
      expect(ballUsageStatusShouldWarn(BallUsageStatus.LIMIT_APPROACHING)).toBe(true);
    });

    it('should return false for OK', () => {
      expect(ballUsageStatusShouldWarn(BallUsageStatus.OK)).toBe(false);
    });

    it('should return false for LIMIT_REACHED', () => {
      expect(ballUsageStatusShouldWarn(BallUsageStatus.LIMIT_REACHED)).toBe(false);
    });
  });

  describe('aiCoachUsageStatusCanUse', () => {
    it('should return true for LIMIT_APPROACHING', () => {
      expect(aiCoachUsageStatusCanUse(AiCoachUsageStatus.LIMIT_APPROACHING)).toBe(true);
    });

    it('should return true for OK', () => {
      expect(aiCoachUsageStatusCanUse(AiCoachUsageStatus.OK)).toBe(true);
    });

    it('should return false for LIMIT_REACHED', () => {
      expect(aiCoachUsageStatusCanUse(AiCoachUsageStatus.LIMIT_REACHED)).toBe(false);
    });
  });
});
